package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;
import java.io.Reader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithFirstRecordAsHeader() {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withDelimiter(null)
                .withEscape(null).withHeader(null).withSkipHeaderRecord(false).withIgnoreSurroundingSpaces(true)
                .withIgnoreEmptyLines(true).withRecordSeparator("\r\n").withNullString(null)
                .withHeaderComments(null).withIgnoreHeaderCase(false).withTrim(false).withTrailingDelimiter(false);

        // When
        CSVFormat result = csvFormat.withFirstRecordAsHeader();

        // Then
        assertTrue(result.getSkipHeaderRecord());
        assertArrayEquals(csvFormat.getHeader(), result.getHeader());
    }

    // Add more test cases for other methods if needed

}
